import{_ as e,o as i,c as s,ao as a}from"./chunks/framework.BwTKejc4.js";const c=JSON.parse('{"title":"Formula grammar","description":"","frontmatter":{},"headers":[],"relativePath":"developer-notes/formula-grammar.md","filePath":"developer-notes/formula-grammar.md","lastUpdated":null}'),r={name:"developer-notes/formula-grammar.md"};function n(l,t,d,h,o,p){return i(),s("div",null,[...t[0]||(t[0]=[a(`<h1 id="Formula-grammar" tabindex="-1">Formula grammar <a class="header-anchor" href="#Formula-grammar" aria-label="Permalink to &quot;Formula grammar {#Formula-grammar}&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Status — Implemented (Gaussian surface)</p><p>Mirrors drmTMB&#39;s <a href="https://itchyshin.github.io/drmTMB/articles/formula-grammar.html" target="_blank" rel="noreferrer">Formula grammar</a>. The grammar below — both <code>bf</code> shapes, the structured markers, and the reserved-syntax rejections — is <strong>live in DRM.jl today</strong>. The Julia column is authoritative (taken from the source); for the R↔Julia spelling map see the <a href="/DRM.jl/dev/rosetta#Rosetta-—-R-Julia">Rosetta — R ↔ Julia</a> page and the <a href="/DRM.jl/dev/r-julia-bridge#R-Julia-bridge">R ↔ Julia bridge</a>.</p></div><p>A DRM.jl model is <strong>one linear-predictor formula per distributional parameter</strong>, bundled by <a href="/DRM.jl/dev/reference/model-specification#DRM.bf"><code>bf</code></a> (alias <code>drm_formula</code>) and handed to <a href="/DRM.jl/dev/reference/model-fitting-and-postfit#DRM.drm"><code>drm</code></a>. This mirrors <code>brms</code> / drmTMB: each formula&#39;s left-hand side names the parameter it predicts. <code>bf</code> has two shapes — a <strong>univariate</strong> positional form and a <strong>bivariate</strong> keyword form.</p><h2 id="Univariate-form" tabindex="-1">Univariate form <a class="header-anchor" href="#Univariate-form" aria-label="Permalink to &quot;Univariate form {#Univariate-form}&quot;">​</a></h2><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">bf</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(y </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x1 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x2, sigma </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x1)</span></span></code></pre></div><ul><li><p>The <strong>first</strong> formula <code>y ~ …</code> sets the <strong>response</strong> column and the <strong>mean <code>μ</code></strong> predictor. The mean is never written as a separate <code>mu ~ …</code> — μ <em>is</em> the response formula.</p></li><li><p>Each <strong>later</strong> formula <code>param ~ …</code> sets that distributional parameter&#39;s predictor. The accepted secondary parameters are:</p><table tabindex="0"><thead><tr><th style="text-align:right;">LHS name</th><th style="text-align:right;">Parameter</th><th style="text-align:right;">Link</th><th style="text-align:right;">Notes</th></tr></thead><tbody><tr><td style="text-align:right;"><code>sigma</code></td><td style="text-align:right;">scale σ</td><td style="text-align:right;">log</td><td style="text-align:right;">defaults to <code>~ 1</code> when omitted; <strong>never <code>tau</code></strong></td></tr><tr><td style="text-align:right;"><code>nu</code></td><td style="text-align:right;">shape/df (e.g. Student-t)</td><td style="text-align:right;">—</td><td style="text-align:right;">family-dependent</td></tr><tr><td style="text-align:right;"><code>zi</code></td><td style="text-align:right;">zero-inflation probability</td><td style="text-align:right;">—</td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;"><code>hu</code></td><td style="text-align:right;">hurdle probability</td><td style="text-align:right;">—</td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;"><code>zoi</code></td><td style="text-align:right;">zero-one-inflation</td><td style="text-align:right;">—</td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;"><code>coi</code></td><td style="text-align:right;">conditional-one-inflation</td><td style="text-align:right;">—</td><td style="text-align:right;"></td></tr></tbody></table><p>Whether a given family actually <em>uses</em> a parameter (e.g. Gaussian has no <code>nu</code>) is a separate, family-level question resolved inside <a href="/DRM.jl/dev/reference/model-fitting-and-postfit#DRM.drm"><code>drm</code></a>.</p></li></ul><p><code>sigma</code> is special: if you omit it, <code>bf</code> appends <code>sigma =&gt; 1</code> automatically, so <code>bf(y ~ x)</code> is <code>bf(y ~ x, sigma ~ 1)</code>.</p><h3 id="Two-column-response" tabindex="-1">Two-column response <a class="header-anchor" href="#Two-column-response" aria-label="Permalink to &quot;Two-column response {#Two-column-response}&quot;">​</a></h3><p>Families that take a count-of-trials response (binomial, beta-binomial) use <code>cbind</code> on the left of the <strong>mean</strong> formula:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">bf</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cbind</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(successes, failures) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x, sigma </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><h3 id="The-implicit-intercept" tabindex="-1">The implicit intercept <a class="header-anchor" href="#The-implicit-intercept" aria-label="Permalink to &quot;The implicit intercept {#The-implicit-intercept}&quot;">​</a></h3><p>DRM.jl follows R&#39;s rule: <code>y ~ x</code> means <code>y ~ 1 + x</code> (an intercept is added). Drop it explicitly with <code>0 + x</code> (or <code>-1</code>):</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">bf</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(y </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x)        </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ⇒ 1 + x   (intercept included)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">bf</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(y </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> +</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x)    </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># no intercept</span></span></code></pre></div><p>This applies to every parameter&#39;s formula, mean and scale alike.</p><h2 id="Random-effects-and-structured-markers" tabindex="-1">Random effects and structured markers <a class="header-anchor" href="#Random-effects-and-structured-markers" aria-label="Permalink to &quot;Random effects and structured markers {#Random-effects-and-structured-markers}&quot;">​</a></h2><p>Random-effect terms use the familiar <code>lme4</code> / <code>brms</code> spelling inside any parameter&#39;s formula:</p><table tabindex="0"><thead><tr><th style="text-align:right;">Term</th><th style="text-align:right;">Meaning</th></tr></thead><tbody><tr><td style="text-align:right;"><code>(1 | g)</code></td><td style="text-align:right;">random intercept by grouping factor <code>g</code></td></tr><tr><td style="text-align:right;"><code>(1 + x | g)</code></td><td style="text-align:right;">correlated random intercept + slope</td></tr><tr><td style="text-align:right;"><code>(0 + x | g)</code></td><td style="text-align:right;">independent random slope</td></tr><tr><td style="text-align:right;"><code>(1 | g) + (1 | h)</code></td><td style="text-align:right;">crossed random intercepts</td></tr></tbody></table><p>Wrapping a random-effect term in a <strong>structured marker</strong> gives it a known correlation or sampling-variance structure:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">bf</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(y </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> phylo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> species))        </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># phylogenetic correlation from a tree</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">bf</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(y </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> spatial</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> site))         </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># spatial correlation from coords</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">bf</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(y </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> animal</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> id))            </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># pedigree relatedness A</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">bf</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(y </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> relmat</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> id))            </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># an arbitrary known relatedness matrix K</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">bf</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(y </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> meta_V</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(v))                     </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># meta-analysis: known sampling variances v</span></span></code></pre></div><p>The marker functions (<code>phylo</code>, <code>spatial</code>, <code>animal</code>, <code>relmat</code>, <code>meta_V</code>) are identity stubs that are <strong>intercepted during formula parsing</strong> — the structure matrix itself (<code>tree</code>, <code>coords</code>, <code>A</code>, <code>K</code>) is supplied as a keyword to <a href="/DRM.jl/dev/reference/model-fitting-and-postfit#DRM.drm"><code>drm</code></a>. See the <a href="/DRM.jl/dev/reference/structured-effect-markers#Structured-effect-markers">Structured-effect markers</a> reference.</p><h2 id="Bivariate-keyword-form" tabindex="-1">Bivariate keyword form <a class="header-anchor" href="#Bivariate-keyword-form" aria-label="Permalink to &quot;Bivariate keyword form {#Bivariate-keyword-form}&quot;">​</a></h2><p>A two-response Gaussian model with a predictor-dependent residual correlation is written with keywords, mirroring drmTMB:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">bf</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(mu1   </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> @formula</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(y1 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x),</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">   mu2   </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> @formula</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(y2 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x),</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">   sigma1 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> @formula</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(sigma1 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x),</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">   sigma2 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> @formula</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(sigma2 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x),</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">   rho12  </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> @formula</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(rho12 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x))</span></span></code></pre></div><ul><li><p><code>mu1</code> / <code>mu2</code> set the two responses and their mean predictors.</p></li><li><p><code>sigma1</code> / <code>sigma2</code> are the two log-scales (log link); they default to <code>~ 1</code>.</p></li><li><p><code>rho12</code> is the <strong>residual</strong> correlation, on a <code>tanh</code> link (its coefficients act on <code>atanh ρ12</code>, keeping <code>ρ12 ∈ (-1, 1)</code>); it defaults to <code>~ 1</code>.</p></li></ul><p>For the σ and ρ formulas, the left-hand side is a <strong>placeholder</strong> that must be the parameter&#39;s own name (<code>sigma1 ~ …</code>, <code>rho12 ~ …</code>); only the right-hand side is used. Group-level correlations (phylo / spatial / study) are <em>named covariance summaries</em>, not this residual <code>rho12</code>.</p><h2 id="Reserved-syntax-rejections" tabindex="-1">Reserved-syntax rejections <a class="header-anchor" href="#Reserved-syntax-rejections" aria-label="Permalink to &quot;Reserved-syntax rejections {#Reserved-syntax-rejections}&quot;">​</a></h2><p>To catch the mistakes drmTMB catches, <code>bf</code> rejects the following with clear, parallel error messages rather than building a wrong model:</p><table tabindex="0"><thead><tr><th style="text-align:right;">You wrote</th><th style="text-align:right;">Rejected because</th></tr></thead><tbody><tr><td style="text-align:right;"><code>sigma</code> mistyped as <code>tau</code></td><td style="text-align:right;">the scale parameter is named <code>sigma</code>, never <code>tau</code></td></tr><tr><td style="text-align:right;"><code>mu ~ …</code> as a separate formula</td><td style="text-align:right;">μ comes from the response formula, not a separate one</td></tr><tr><td style="text-align:right;"><code>mu1</code>/<code>mu2</code>/<code>sigma1</code>/<code>sigma2</code>/<code>rho12</code> in the <strong>positional</strong> form</td><td style="text-align:right;">these are two-response parameters — use the keyword form</td></tr><tr><td style="text-align:right;">an unknown name (e.g. <code>theta ~ …</code>)</td><td style="text-align:right;">not a valid distributional parameter (the message lists the valid names)</td></tr><tr><td style="text-align:right;">the same parameter twice</td><td style="text-align:right;">one formula per distributional parameter</td></tr><tr><td style="text-align:right;">a bivariate placeholder LHS that isn&#39;t its own name (e.g. <code>sigma1 = @formula(tau ~ x)</code>, or swapped <code>sigma1</code>/<code>sigma2</code>)</td><td style="text-align:right;">each keyword&#39;s placeholder LHS must match its parameter</td></tr><tr><td style="text-align:right;"><code>cbind(…)</code> response on <code>mu1</code>/<code>mu2</code></td><td style="text-align:right;">the bivariate form takes one response per mean (<code>cbind</code> is univariate-only)</td></tr></tbody></table><p>These rejections are front-end only — they never reach the fitter. See the parity tests in <code>test/test_bf_grammar.jl</code>.</p>`,29)])])}const g=e(r,[["render",n]]);export{c as __pageData,g as default};
